const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at);
const produkte = {};
let umsatz = 0;
for (const o of orders) {
  umsatz += parseFloat(o.total_price || 0);
  for (const li of (o.line_items || [])) produkte[li.title] = (produkte[li.title] || 0) + li.quantity;
}
const top = Object.entries(produkte).sort((a, b) => b[1] - a[1]).slice(0, 5)
  .map(([n, m]) => n + ' (' + m + 'x)').join(', ');

const monate = ['Januar','Februar','Maerz','April','Mai','Juni','Juli','August','September','Oktober','November','Dezember'];
const jetzt = new Date();
const folgemonatIndex = (jetzt.getMonth() + 1) % 12;
const folgemonat = monate[folgemonatIndex];
const jahr = folgemonatIndex === 0 ? jetzt.getFullYear() + 1 : jetzt.getFullYear();

const prompt = 'Du bist Marketing-Stratege fuer den Onlineshop "' + setup.SHOP_NAME + '" (Nische: ' + setup.SHOP_NISCHE + ', Zielgruppe: ' + setup.ZIELGRUPPE + ', Markt: Deutschland/DACH).\n' +
  'Letzte 30 Tage: ' + orders.length + ' Bestellungen, ' + umsatz.toFixed(0) + ' Umsatz. Top-Produkte: ' + (top || 'keine') + '\n\n' +
  'Erstelle den kompletten MARKETING-KALENDER fuer ' + folgemonat + ' ' + jahr + ', auf Deutsch:\n\n' +
  '1. SAISON-CHECK: Welche Feiertage, Saison-Momente, Shopping-Events und kulturellen Anlaesse gibt es im ' + folgemonat + ' im DACH-Raum, die fuer diese Nische relevant sind? (auch inoffizielle wie Aktionstage, Wetterwechsel, Gehaltseingaenge am Monatsanfang/-ende)\n' +
  '2. WOCHENPLAN: Fuer jede der 4 Wochen ein Marketing-Thema mit Content-Fokus (an die Saison-Momente angedockt)\n' +
  '3. ZWEI PROMO-AKTIONEN: mit konkretem Datum, Mechanik (Rabatt/Bundle/Gratis-Versand), Begruendung und passendem Rabattcode-Vorschlag\n' +
  '4. CONTENT-HIGHLIGHTS: 5 konkrete Video-/Post-Ideen, die den Monat besonders machen\n' +
  '5. E-MAIL-PLAN: Welche Mails in welcher Woche (passt zu den Promos)\n' +
  '6. MONATSZIEL-VORSCHLAG: realistisches Umsatzziel basierend auf den letzten 30 Tagen (+X%), mit kurzer Rechnung\n\n' +
  'Antworte als sauberes HTML (h2/h3, Listen, Tabellen wo sinnvoll, ohne html/body-Geruest, kein Markdown-Codeblock) - wird direkt als E-Mail verschickt.';

return [{ json: { prompt, folgemonat: folgemonat + ' ' + jahr } }];

const blocks = $json.content || [];
const html = (blocks.find(b => b.type === 'text') || {}).text || '';
const setup = $('⚙️ Setup').first().json;
const monat = $('🧠 Folgemonat + Datenbasis').item.json.folgemonat;
return { json: {
  betreff: '🗓️ Dein Marketing-Kalender fuer ' + monat + ' · ' + setup.SHOP_NAME,
  email_html: '<div style="font-family:sans-serif;max-width:640px;margin:0 auto;">' + html.replace(/```html|```/g, '') + '</div>'
}};
